function solve(nums) {
    let total_x_sum = 0;
    const n = nums.length;

    if (n <= 1) {
        return 0;
    }

    // The minimum total sum of x is the sum of all positive differences nums[i-1] - nums[i].
    for (let i = 1; i < n; i++) {
        const difference = nums[i - 1] - nums[i];
        if (difference > 0) {
            total_x_sum += difference;
        }
    }

    return total_x_sum;
}

